function answer(instruction, instructor, depth=0):
    plan = assistant.analyse(instruction)

    if plan.is_missing_deciding_context() and depth < MAX_REVERSALS:
        # role reversal: assistant becomes the asker
        question = assistant.formulate_one_question(plan.gap)
        clarification = instructor.answer(question)

        # recurse with augmented instruction, capped by depth
        return answer(
            instruction=instruction + clarification,
            instructor=instructor,
            depth=depth + 1,
        )

    # either no gap, or depth budget reached; commit to an answer
    return assistant.produce_conclusion(instruction, plan)

