function dispatch(envelope):
    # envelope = {from, to, intent, payload_schema, payload, trace_id}
    target = domain_agents[envelope.to]
    validate(envelope.payload, envelope.payload_schema)   # A2A / MCP-style
    return target.handle(envelope)

function router(user_request):
    entry_domain = classify_domain(user_request)
    artefact = domain_agents[entry_domain].handle(
        Envelope(to=entry_domain, intent="answer", payload=user_request))
    while artefact.requires_handoff:
        artefact = dispatch(artefact.next_envelope)
    return artefact.value

