from metagpt.actions import Action, UserRequirement
from metagpt.environment import Environment
from metagpt.roles import Role
from metagpt.schema import Message


class SplitTask(Action):
    async def run(self, with_messages, **kwargs):
        return ["subtask-a", "subtask-b"]


class DoSubtask(Action):
    async def run(self, with_messages, **kwargs):
        return f"done: {with_messages[-1].content}"


class Planner(Role):
    def __init__(self, **kwargs):
        super().__init__(**kwargs)
        self.set_actions([SplitTask])
        self._watch({UserRequirement})              # subscribe

    async def _act(self) -> Message:
        subtasks = await self.rc.todo.run(self.rc.history)
        for s in subtasks:
            self.rc.env.publish_message(           # publish
                Message(content=s, cause_by=SplitTask)
            )
        return Message(content="dispatched")


class Worker(Role):
    def __init__(self, **kwargs):
        super().__init__(**kwargs)
        self.set_actions([DoSubtask])
        self._watch({SplitTask})                    # subscribes by cause_by


