class TeamMember:
    function pursue(goal):
        while team_status[goal.id] == "active":
            belief = self.update_beliefs(goal)

            # joint-commitment clauses (a)+(b) made explicit:
            if belief.achieved:
                team_bus.publish(Notify(goal.id, by=self.id, reason="achieved"))
                break
            if belief.impossible:
                team_bus.publish(Notify(goal.id, by=self.id, reason="impossible"))
                break
            if belief.irrelevant:
                team_bus.publish(Notify(goal.id, by=self.id, reason="irrelevant"))
                break

            self.act_toward(goal)                          # otherwise, keep pursuing

    function on_team_notify(msg):
        # any member's notification ends the team's pursuit — no silent abandonment
        team_status[msg.goal_id] = msg.reason
        self.abort_work_on(msg.goal_id)

function form_team(goal, members):
    team_status[goal.id] = "active"
    for m in members:
        team_bus.subscribe(m.on_team_notify)
        spawn(m.pursue(goal))

# Lifecycle: forming -> active -> {satisfied, impossible, abandoned}
# Transition is always TRIGGERED BY A NOTIFY MESSAGE, never silent.

# Why this works: the meta-commitment is part of the contract, so a member who
# learns the goal is impossible cannot just stop — it must notify, which lets
# every other member abort cleanly and stops wasted parallel effort and stale
# outputs from the rest of the team.
# Related: see `commitment-tracking`, `coalition-formation`, `bdi-agent`.

