function orchestrator(task):
    # decomposition is decided after we see the task,
    # not pre-baked in a static plan
    subtasks = llm.decompose(task)          # returns list of {goal, role}
    if not subtasks:
        return llm.answer(task)

    results = []
    for sub in subtasks:                    # could be fan-out in parallel
        worker = spawn_worker(role=sub.role, tools=tools_for(sub.role))
        results.append(worker.run(sub.goal))

    return llm.synthesise(task, results)    # orchestrator reconciles

