# Inference loop (the conductor has already been RL-trained)
function conductor_run(task, depth=0):
    history = [task]
    for step in 1..STEP_BUDGET:
        sub_task, worker_id = conductor.policy(history)   # small RL model

        if worker_id == "FINAL":
            return conductor.finalise(history)

        if worker_id == "CONDUCTOR" and depth < MAX_RECURSION:
            output = conductor_run(sub_task, depth + 1)   # self as worker
        else:
            output = WORKER_POOL[worker_id].run(sub_task)

        history.append({"sub_task": sub_task,
                        "worker":   worker_id,
                        "output":   output})

    return conductor.finalise(history)

