        lane = classify(request)               # supervisor LLM call
        if lane == "answer_directly":
            return supervisor_reply(request)

        result = specialists[lane].run(request)
        if result.is_resolved:
            return result.message              # supervisor aggregates / forwards

        request = result.followup              # supervisor may re-dispatch

    return escalate_to_human(request)          # bounded by MAX_HOPS

