function peer_loop(agent, bus):
    while not environment.terminated():
        msg = bus.recv(filter=agent.subscriptions)
        action = agent.policy.decide(msg, agent.state)
        bus.send(action)
        agent.state = agent.policy.update(agent.state, action, msg)

# termination is environment-level
function environment.terminated():
    return (time_budget_exceeded()
            or consensus_reached(bus.recent())
            or external_stop_signal())

shared_memory = SharedStore()        # versioned reads/writes
reasoner_jobs = AsyncQueue()

function talker_turn(user_msg):
    state = shared_memory.snapshot()  # never blocks on Reasoner
    intent = classify(user_msg, state)

    if intent.needs_deliberation:
        # fire-and-forget: Reasoner runs out of band
        reasoner_jobs.put(Job(task=user_msg, ctx=state))
        return talker_llm.respond(
            user_msg,
            state,
            hint="acknowledge + ask one clarifier; do not promise results",
        )

    # also surface any progress the Reasoner has written since last turn
    if state.has_new_reasoner_conclusions():
        return talker_llm.respond(user_msg, state,
                                  hint="weave in new conclusions naturally")

    return talker_llm.respond(user_msg, state)

async function reasoner_loop():
    while not stopped:
        job = await reasoner_jobs.get()
        conclusions = reasoner_llm.deliberate(
            job.task, job.ctx,
            tools=PLANNING_AND_TOOL_USE,
            budget=LONG_BUDGET,
        )
        shared_memory.write(
            key=f"reasoner.{job.id}",
            value=conclusions,
            version=now(),
        )                              # Talker picks it up on next turn

